from elasticsearch import Elasticsearch

# Initialize Elasticsearch client
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

# Create an index
def create_index(index_name):
    if not es.indices.exists(index=index_name):
        es.indices.create(index=index_name)

# Index a document
def index_document(index_name, doc_id, body):
    es.index(index=index_name, id=doc_id, body=body)

# Search documents
def search_documents(index_name, query):
    results = es.search(index=index_name, body={'query': query})
    return results['hits']['hits']

# Log aggregation
def log_aggregation(index_name, logs):
    for log in logs:
        index_document(index_name, log['id'], log)

# Example usage
if __name__ == "__main__":
    index_name = 'logs'
    create_index(index_name)
    
    # Sample log data
    logs = [
        {'id': 1, 'message': 'Error occurred', 'level': 'ERROR'},
        {'id': 2, 'message': 'Warning message', 'level': 'WARNING'}
    ]
    
    log_aggregation(index_name, logs)
    
    # Search for all error messages
    search_query = {
        "match": {
            "level": "ERROR"
        }
    }
    results = search_documents(index_name, search_query)
    
    for result in results:
        print(result['_source'])